import React from "react";
import {
  Instagram,
  Facebook,
  Twitter,
  Youtube,
  Mail,
  Phone,
  MapPin,
} from "lucide-react";
import { motion } from "framer-motion";

const Footer = () => {
  const currentYear = new Date().getFullYear();

  const socialLinks = [
    { icon: Instagram, label: "Instagram", href: "#" },
    { icon: Facebook, label: "Facebook", href: "#" },
    { icon: Twitter, label: "Twitter", href: "#" },
    { icon: Youtube, label: "YouTube", href: "#" },
  ];

  const footerSections = [
    {
      title: "Visit Us",
      items: ["Artistic Hub,", "Downtown West,", "New Delhi - 110001"],
      icon: MapPin,
    },
    {
      title: "Contact",
      items: ["info@dodstudio.com", "+91 999 000 1111"],
      icon: Mail,
    },
    {
      title: "Academy",
      items: ["Kids Batches", "Teens & Adults", "Pro Intensives"],
    },
    {
      title: "Services",
      items: ["Wedding Sangeet", "Corporate Shows", "Visual Studio"],
    },
  ];

  const containerVariants = {
    hidden: { opacity: 0 },
    visible: {
      opacity: 1,
      transition: {
        staggerChildren: 0.1,
        delayChildren: 0.2,
      },
    },
  };

  const itemVariants = {
    hidden: { opacity: 0, y: 20 },
    visible: {
      opacity: 1,
      y: 0,
      transition: { duration: 0.5 },
    },
  };

  return (
    <footer className="relative bg-charcoal border-t border-gold/20 overflow-hidden">
      {/* Background Gradient */}
      <div className="absolute inset-0 -z-10">
        <div className="absolute top-0 right-0 w-96 h-96 bg-gold/5 rounded-full blur-3xl" />
        <div className="absolute bottom-0 left-0 w-96 h-96 bg-gold/3 rounded-full blur-3xl" />
      </div>

      {/* Main Footer Content */}
      <div className="max-w-7xl mx-auto px-6 lg:px-12 py-20 md:py-24">
        {/* Top Section - Logo & Tagline */}
        <motion.div
          initial={{ opacity: 0, y: 30 }}
          whileInView={{ opacity: 1, y: 0 }}
          viewport={{ once: true }}
          className="flex flex-col items-center mb-20"
        >
          <div className="font-cinzel text-5xl md:text-6xl font-bold text-gold-gradient mb-4 tracking-[0.15em]">
            DOD
          </div>
          <p className="text-gold tracking-[0.4em] uppercase text-xs font-light">
            Dream of Dance Studio
          </p>
          <div className="h-px w-32 bg-gradient-to-r from-transparent via-gold to-transparent mt-8" />
        </motion.div>

        {/* Social Links */}
        <motion.div
          initial={{ opacity: 0, scale: 0.8 }}
          whileInView={{ opacity: 1, scale: 1 }}
          viewport={{ once: true }}
          className="flex justify-center gap-8 mb-20"
        >
          {socialLinks.map((social, index) => {
            const Icon = social.icon;
            return (
              <motion.a
                key={social.label}
                href={social.href}
                whileHover={{ scale: 1.2, rotate: 5 }}
                whileTap={{ scale: 0.95 }}
                className="w-12 h-12 rounded-full border border-gold/30 flex items-center justify-center text-gold/60 hover:text-gold hover:border-gold transition-all duration-300 group"
              >
                <Icon
                  size={20}
                  strokeWidth={1.5}
                  className="group-hover:animate-spin-slow"
                />
              </motion.a>
            );
          })}
        </motion.div>

        {/* Footer Grid */}
        <motion.div
          variants={containerVariants}
          initial="hidden"
          whileInView="visible"
          viewport={{ once: true }}
          className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-12 md:gap-8 mb-20"
        >
          {footerSections.map((section, index) => {
            const Icon = section.icon;
            return (
              <motion.div
                key={index}
                variants={itemVariants}
                className="flex flex-col items-center md:items-start text-center md:text-left group"
              >
                {Icon && (
                  <div className="mb-4 p-3 rounded-lg bg-gold/10 border border-gold/20 group-hover:border-gold/50 transition-all duration-300">
                    <Icon className="w-5 h-5 text-gold" strokeWidth={1.5} />
                  </div>
                )}
                <h5 className="font-cinzel text-gold tracking-widest text-sm uppercase font-semibold mb-4">
                  {section.title}
                </h5>
                <div className="space-y-2">
                  {section.items.map((item, idx) => (
                    <p
                      key={idx}
                      className="text-xs text-ivory/60 leading-relaxed font-light hover:text-gold transition-colors duration-300"
                    >
                      {item}
                    </p>
                  ))}
                </div>
              </motion.div>
            );
          })}
        </motion.div>

        {/* Divider */}
        <div className="h-px w-full bg-gradient-to-r from-transparent via-gold/30 to-transparent mb-12" />

        {/* Bottom Section */}
        <motion.div
          initial={{ opacity: 0 }}
          whileInView={{ opacity: 1 }}
          viewport={{ once: true }}
          className="flex flex-col md:flex-row items-center justify-between"
        >
          <p className="text-[11px] text-ivory/40 uppercase tracking-[0.25em] font-light mb-6 md:mb-0">
            © {currentYear} Dream of Dance. Curated for Artists.
          </p>

          <div className="flex items-center space-x-6 text-[11px] text-ivory/40 uppercase tracking-widest font-light">
            <a
              href="#"
              className="hover:text-gold transition-colors duration-300"
            >
              Privacy
            </a>
            <span className="text-gold/20">•</span>
            <a
              href="#"
              className="hover:text-gold transition-colors duration-300"
            >
              Terms
            </a>
            <span className="text-gold/20">•</span>
            <a
              href="#"
              className="hover:text-gold transition-colors duration-300"
            >
              Sitemap
            </a>
          </div>
        </motion.div>
      </div>

      {/* Subtle Pattern Overlay */}
      <div className="absolute inset-0 opacity-[0.02] pointer-events-none">
        <div
          className="absolute inset-0"
          style={{
            backgroundImage:
              "radial-gradient(circle at 1px 1px, #D4AF37 1px, transparent 1px)",
            backgroundSize: "50px 50px",
          }}
        />
      </div>
    </footer>
  );
};

export default Footer;
